  const relationMap=new Map();current.forEach((item,rater)=>{(payloadOf(item).relationships||[]).forEach(row=>relationMap.set(`${rater}:${Number(row.targetNumber)}`,Number(row.score)))});const incoming=new Map();relationMap.forEach((score,key)=>{const target=Number(key.split(':')[1]);if(!incoming.has(target))incoming.set(target,[]);incoming.get(target).push(score)});incoming.forEach((values,target)=>{if(values.length<4)return;const low=values.filter(value=>value<=2).length/values.length;const high=values.filter(value=>value>=4).length/values.length;const sd=standardDeviation(values);if(low>=.25&&high>=.25&&sd>=1.3){const student=classSettings.students.find(row=>Number(row.number)===target);add('week',{student_name:student?.name||`${target}번 학생`},'친구에 따라 관계 경험이 다르게 나타나요',`1~2점 ${Math.round(low*100)}% · 4~5점 ${Math.round(high*100)}% · 표준편차 ${sd.toFixed(1)}`,[`수신 관계 응답 ${values.length}건: ${values.join(', ')}점`,`평균 ${(values.reduce((a,b)=>a+b,0)/values.length).toFixed(1)}점 · 표준편차 ${sd.toFixed(1)}`],['친구 집단별 상호작용 차이','활동 상황에 따른 관계 경험 차이','응답 시점의 감정 차이'],'모둠과 놀이 집단에 따라 말투·접근·상대 반응이 달라지는지 확인합니다.')}});
  const checkedPairs=new Set();relationMap.forEach((score,key)=>{const [a,b]=key.split(':').map(Number);const pair=[a,b].sort((x,y)=>x-y).join(':');if(checkedPairs.has(pair))return;checkedPairs.add(pair);const reverse=relationMap.get(`${b}:${a}`);if(reverse!==undefined&&Math.abs(score-reverse)>=2){const aName=classSettings.students.find(row=>Number(row.number)===a)?.name||`${a}번`;const bName=classSettings.students.find(row=>Number(row.number)===b)?.name||`${b}번`;add('watch',{student_name:`${aName} ↔ ${bName}`},'서로 느끼는 관계에 차이가 있어요',`${aName}→${bName} ${score}점 · ${bName}→${aName} ${reverse}점`,[`방향별 관계 점수 차이 ${Math.abs(score-reverse)}점`],['관계 기대의 차이','접근·거절 신호에 대한 이해 차이','응답 시점의 일시적인 감정'],'두 학생을 따로 살펴보고 서로의 접근과 반응을 어떻게 느끼는지 자연스럽게 확인합니다.')}});
  const previousRelationMap=new Map();previous.forEach((item,rater)=>{(payloadOf(item).relationships||[]).forEach(row=>previousRelationMap.set(`${rater}:${Number(row.targetNumber)}`,Number(row.score)))});
  const mutualHighCount=(map,number)=>classSettings.students.filter(student=>Number(student.number)!==number).filter(student=>{const other=Number(student.number);return map.get(`${number}:${other}`)>=4&&map.get(`${other}:${number}`)>=4}).length;
  const positiveMentions=new Map();current.forEach(item=>{const peer=payloadOf(item).peerObservations||{};const text=`${peer.kind?.detail||''} ${peer.growth?.detail||''}`;names.forEach(name=>{if(text.includes(name))positiveMentions.set(name,(positiveMentions.get(name)||0)+1)})});
  classSettings.students.forEach(student=>{const number=Number(student.number);const values=incoming.get(number)||[];if(values.length<4)return;const highCount=values.filter(value=>value>=4).length;const highRatio=highCount/values.length;const mutualNow=mutualHighCount(relationMap,number);const mutualBefore=mutualHighCount(previousRelationMap,number);const unreciprocated=classSettings.students.filter(other=>Number(other.number)!==number).filter(other=>relationMap.get(`${number}:${Number(other.number)}`)>=4&&relationMap.get(`${Number(other.number)}:${number}`)<=2).length;const own=payloadOf(current.get(number));const relationWorry=/친구|관계|혼자|놀/.test(String(own.studentState?.worryDetail||''));const helpCount=new Set((helpMentions.get(student.name)||[]).map(({item})=>Number(item.student_number||payloadOf(item).studentNumber))).size;const relationFlags=[];if(mutualNow<=1)relationFlags.push(`상호 4~5점 연결 ${mutualNow}명`);if(highRatio<=.25)relationFlags.push(`받은 4~5점 ${highCount}/${values.length}건`);if(mutualBefore-mutualNow>=2)relationFlags.push(`상호 높은 연결 ${mutualBefore}→${mutualNow}명`);if(unreciprocated>=2)relationFlags.push(`본인은 높게 평가했지만 되돌아온 점수가 낮은 관계 ${unreciprocated}명`);const contextFlags=[];if(relationWorry)contextFlags.push('본인이 친구 관계 고민을 작성함');if(helpCount>=2)contextFlags.push(`서로 다른 친구 ${helpCount}명이 도움 필요로 언급`);if(relationFlags.length&&relationFlags.length+contextFlags.length>=2){const urgentContext=relationWorry||helpCount>=2||mutualBefore-mutualNow>=2;add(urgentContext?'week':'watch',{student_name:student.name,student_number:number},'관계 연결을 실제 상황에서 확인해 주세요',[...relationFlags,...contextFlags].join(' · '),[...relationFlags,...contextFlags,`수신 관계 점수 ${values.length}건 · 평균 ${(values.reduce((sum,value)=>sum+value,0)/values.length).toFixed(1)}점`],['최근 자리·모둠·놀이 상대의 변화','특정 활동에서만 관계가 이어지는 상황','응답하지 않은 친구와 실제로 친밀할 가능성'],'5일 동안 쉬는 시간 3회와 모둠 활동 2회에서 먼저 접근하는 친구, 상대 반응, 혼자 있는 시간과 참여 기회를 사실 중심으로 기록합니다.')}});
  found.forEach(signal=>{const student=classSettings.students.find(row=>row.name===signal.name);if(!student){signal.protectiveFactors=[];return}const number=Number(student.number);const values=incoming.get(number)||[];const mutual=mutualHighCount(relationMap,number);const positive=positiveMentions.get(student.name)||0;signal.protectiveFactors=[mutual>=2?`상호 높은 관계 ${mutual}명`:null,values.filter(value=>value>=4).length>=2?`받은 4~5점 ${values.filter(value=>value>=4).length}건`:null,positive?`친절·성장 긍정 언급 ${positive}건`:null].filter(Boolean)});
  return found.sort((a,b)=>({urgent:0,week:1,watch:2}[a.type]-{urgent:0,week:1,watch:2}[b.type]));
