function groupedSignals(filter='all'){const groups=new Map();signals.forEach(signal=>{if(!groups.has(signal.name))groups.set(signal.name,[]);groups.get(signal.name).push(signal)});return[...groups.entries()].map(([name,items])=>{const type=items.some(item=>item.type==='urgent')?'urgent':items.some(item=>item.type==='week')?'week':'watch';const student=classSettings.students.find(row=>row.name===name);const hasPrevious=student&&latestByStudent(allResponses,previousMonth(selectedAnalysisMonth)).has(Number(student.number));const changed=items.some(item=>item.evidence.some(evidence=>String(evidence).includes('→')));const trend=!hasPrevious?'전월 비교 자료 없음':changed?'전월 대비 변화 확인':'이번 달 확인 신호';const protectiveFactors=[...new Set(items.flatMap(item=>item.protectiveFactors||[]))];return{name,items,type,tag:signalTag(type),ids:items.map(item=>item.id),trend,protectiveFactors}}).filter(group=>filter==='all'||group.type===filter).sort((a,b)=>({urgent:0,week:1,watch:2}[a.type]-{urgent:0,week:1,watch:2}[b.type]))}
function buildRelationshipAnalysis(responses,month){const current=latestByStudent(responses,month);const total=classSettings.students.length;const submitted=current.size;const relationResponders=[...current.entries()].filter(([,item])=>(payloadOf(item).relationships||[]).length);const ready=total>0&&submitted/total>=.8&&relationResponders.length/total>=.8;const scores=new Map();relationResponders.forEach(([rater,item])=>(payloadOf(item).relationships||[]).forEach(row=>scores.set(`${rater}:${Number(row.targetNumber)}`,Number(row.score))));const students=classSettings.students.filter(student=>current.has(Number(student.number))||[...scores.keys()].some(key=>Number(key.split(':')[1])===Number(student.number)));const mutual=[];students.forEach((student,index)=>students.slice(index+1).forEach(other=>{const a=Number(student.number),b=Number(other.number),ab=scores.get(`${a}:${b}`),ba=scores.get(`${b}:${a}`);if(ab>=4&&ba>=4)mutual.push({a,b,strength:Math.min(ab,ba)})}));const adjacency=new Map(students.map(student=>[Number(student.number),new Set()]));mutual.filter(edge=>edge.strength===5).forEach(edge=>{adjacency.get(edge.a)?.add(edge.b);adjacency.get(edge.b)?.add(edge.a)});const visited=new Set();const groups=[];students.forEach(student=>{const start=Number(student.number);if(visited.has(start))return;const stack=[start],component=[];visited.add(start);while(stack.length){const value=stack.pop();component.push(value);(adjacency.get(value)||[]).forEach(next=>{if(!visited.has(next)){visited.add(next);stack.push(next)}})}if(component.length>=2)groups.push(component)});const groupByStudent=new Map();groups.forEach((group,index)=>group.forEach(number=>groupByStudent.set(number,index)));const connectors=students.map(student=>{const number=Number(student.number);const touched=new Set();mutual.filter(edge=>edge.a===number||edge.b===number).forEach(edge=>{const other=edge.a===number?edge.b:edge.a;const group=groupByStudent.get(other);if(group!==undefined)touched.add(group)});return{number,name:student.name,groups:[...touched],connections:mutual.filter(edge=>edge.a===number||edge.b===number).length}}).filter(item=>item.groups.length>=2);const peripheral=students.map(student=>{const number=Number(student.number);return{number,name:student.name,connections:mutual.filter(edge=>edge.a===number||edge.b===number).length,group:groupByStudent.get(number)}}).filter(item=>item.connections<=1&&item.group===undefined);const groupMetrics=[];for(let i=0;i<groups.length;i++)for(let j=i+1;j<groups.length;j++){const between=[];groups[i].forEach(a=>groups[j].forEach(b=>{const ab=scores.get(`${a}:${b}`),ba=scores.get(`${b}:${a}`);if(ab)between.push(ab);if(ba)between.push(ba)}));const internal=[];[groups[i],groups[j]].forEach(group=>group.forEach((a,index)=>group.slice(index+1).forEach(b=>{const ab=scores.get(`${a}:${b}`),ba=scores.get(`${b}:${a}`);if(ab)internal.push(ab);if(ba)internal.push(ba)})));if(between.length&&internal.length){const betweenAvg=between.reduce((sum,value)=>sum+value,0)/between.length;const internalAvg=internal.reduce((sum,value)=>sum+value,0)/internal.length;if(internalAvg-betweenAvg>=1.2)groupMetrics.push({a:i,b:j,internalAvg,betweenAvg})}}return{ready,total,submitted,relationCount:relationResponders.length,students,scores,mutual,groups,groupByStudent,connectors,peripheral,groupMetrics}}
function renderRelationships(){const content=$('#relationContent');const confidence=$('#relationConfidence');if(!content||!confidence)return;const analysis=buildRelationshipAnalysis(allResponses,selectedAnalysisMonth);const rate=analysis.total?Math.round(analysis.submitted/analysis.total*100):0;const relationRate=analysis.total?Math.round(analysis.relationCount/analysis.total*100):0;confidence.className=`confidence ${analysis.ready?'good':''}`;confidence.textContent=analysis.ready?`분석 가능 · 제출 ${rate}% · 관계 문항 ${relationRate}%`:`데이터 부족 · 제출 ${rate}% · 관계 문항 ${relationRate}%`;if(!analysis.ready){content.innerHTML='<div class="notice warning relation-warning"><span>!</span><div><strong>관계 구조를 해석하기에는 데이터가 부족합니다.</strong><p>개별 도움 요청은 확인할 수 있지만, 제출률과 관계 문항 작성률이 모두 80% 이상일 때 추정 집단과 관계망을 표시합니다.</p></div></div>';return}const width=900,height=480;const positions=new Map();const palette=['#d9edf4','#e8e0f4','#dff3e9','#fff0d8','#f7dfe3'];analysis.groups.forEach((group,index)=>{const centerX=150+(index%4)*210,centerY=130+Math.floor(index/4)*210;group.forEach((number,nodeIndex)=>{const angle=2*Math.PI*nodeIndex/group.length;positions.set(number,{x:centerX+Math.cos(angle)*70,y:centerY+Math.sin(angle)*70,group:index})})});const unplaced=analysis.students.filter(student=>!positions.has(Number(student.number)));unplaced.forEach((student,index)=>positions.set(Number(student.number),{x:100+(index%8)*100,y:height-55-Math.floor(index/8)*75,group:-1}));const lines=analysis.mutual.map(edge=>{const a=positions.get(edge.a),b=positions.get(edge.b);const cross=a.group!==b.group;return`<line class="${cross?'bridge':''}" x1="${a.x}" y1="${a.y}" x2="${b.x}" y2="${b.y}"/>`}).join('');const nodes=analysis.students.map((student,index)=>{const pos=positions.get(Number(student.number));const fill=pos.group>=0?palette[pos.group%palette.length]:'#eef1f3';return`<g transform="translate(${pos.x} ${pos.y})" data-student-node><circle r="25" style="fill:${fill}"/><text>${String.fromCharCode(65+index%26)}</text><title>${escapeHTML(student.name)}</title></g>`}).join('');const groupCards=analysis.groups.length?analysis.groups.map((group,index)=>`<article><strong>추정 집단 ${index+1} · ${group.length}명</strong><p>${group.map(number=>escapeHTML(classSettings.students.find(student=>Number(student.number)===number)?.name||`${number}번`)).join(', ')}</p></article>`).join(''):'<p class="muted">상호 5점 연결을 중심으로 구분되는 추정 집단이 없습니다.</p>';content.innerHTML=`<div class="relation-grid actual-relations"><div class="panel network-panel"><div class="panel-head"><div><p class="eyebrow">실제 월별 응답</p><h3>${monthLabel(selectedAnalysisMonth)} 관계망</h3></div><button class="text-button" id="toggleNames">이름 표시</button></div><div class="network" id="network" aria-label="학생 관계망 추정도"><svg viewBox="0 0 ${width} ${height}" role="img"><g class="links">${lines}</g><g class="nodes">${nodes}</g></svg></div><p class="muted">상호 4~5점 연결을 표시하고, 상호 5점 연결이 이어지는 묶음을 추정 집단으로 계산했습니다.</p></div><div class="relation-notes"><div class="panel"><span class="tag open">추정 집단 ${analysis.groups.length}개</span><h3>상호 높은 관계가 밀집된 묶음</h3><div class="group-list">${groupCards}</div><p class="muted">친한 무리나 고정 집단을 확정한 결과가 아닙니다.</p></div><div class="panel"><span class="tag blue-tag">집단 연결 역할 가능 ${analysis.connectors.length}명</span><h3>여러 집단과 연결된 학생</h3><p>${analysis.connectors.length?analysis.connectors.map(item=>`${escapeHTML(item.name)} (${item.groups.map(group=>`집단 ${group+1}`).join('·')})`).join('<br>'):'뚜렷한 후보 없음'}</p><p class="muted">관계 조정 부담이 있는지도 함께 관찰해 주세요.</p></div><div class="panel"><span class="tag watch">관계 연결 확인 ${analysis.peripheral.length}명</span><h3>강한 상호 연결이 적은 학생</h3><p>${analysis.peripheral.length?analysis.peripheral.map(item=>`${escapeHTML(item.name)} · 상호 연결 ${item.connections}명`).join('<br>'):'뚜렷한 후보 없음'}</p><p class="muted">실제 놀이·모둠 참여를 확인하기 위한 후보이며, 고립을 의미하지 않습니다.</p></div><div class="panel"><span class="tag orange-tag">집단 간 관계 차이 ${analysis.groupMetrics.length}건</span><h3>집단별 관계 경험 차이</h3><p>${analysis.groupMetrics.length?analysis.groupMetrics.map(item=>`집단 ${item.a+1}↔${item.b+1} · 내부 ${item.internalAvg.toFixed(1)} / 집단 간 ${item.betweenAvg.toFixed(1)}`).join('<br>'):'뚜렷한 차이 없음'}</p><p class="muted">모둠·체육·놀이 상황의 경쟁이나 배제 여부를 실제로 확인해 주세요.</p></div></div></div>`}
function renderAnalysisStatus(){const current=latestByStudent(allResponses,selectedAnalysisMonth);const total=classSettings.students.length;const submitted=current.size;const rate=total?Math.round(submitted/total*100):0;const monthlyRows=allResponses.filter(item=>monthOf(item)===selectedAnalysisMonth);const duplicateCount=Math.max(0,monthlyRows.length-submitted);const relationshipCount=[...current.values()].filter(item=>(payloadOf(item).relationships||[]).length).length;const relationshipRate=total?Math.round(relationshipCount/total*100):0;const relationshipReady=rate>=80&&relationshipCount>=Math.ceil(total*.8);const concernCounts={친구:0,공부:0,성적:0,등하교:0,가정:0};current.forEach(item=>{const text=String(payloadOf(item).studentState?.worryDetail||'');Object.keys(concernCounts).forEach(key=>{if(text.includes(key))concernCounts[key]++})});const concerns=Object.entries(concernCounts).filter(([,count])=>count).sort((a,b)=>b[1]-a[1]).map(([key,count])=>`${key} ${count}건`).join(' · ')||'분류된 공통 고민 없음';const el=$('#analysisDataStatus');el.className=`notice ${relationshipReady?'safe':'warning'}`;el.innerHTML=`<span>${relationshipReady?'✓':'!'}</span><div><strong>${monthLabel(selectedAnalysisMonth)} 데이터 상태 · 제출 ${submitted}/${total}명 (${rate}%) · 관계 문항 ${relationshipCount}/${total}명 (${relationshipRate}%)</strong><p>학생별 최신 제출을 분석합니다${duplicateCount?` · 추가 제출 ${duplicateCount}건은 최신 응답으로 대체됨`:''}. 관계 구조 분석: <b>${relationshipReady?'참고 가능':'데이터 부족'}</b>${relationshipReady?'':' (제출·관계 문항 응답률 80% 이상 필요)'} · 공통 고민: ${escapeHTML(concerns)}</p></div>`}
function loadClassSettings(){try{const saved=JSON.parse(localStorage.getItem('ieum-class-settings'));if(saved?.students?.length)return{...defaultSettings,...saved,students:saved.students.map((student,index)=>({...student,accessCode:student.accessCode||String(731204+index*7919).slice(-6)}))}}catch(error){}return JSON.parse(JSON.stringify(defaultSettings))}
function persistClassSettings(){const{teacherSecret,...safeSettings}=classSettings;localStorage.setItem('ieum-class-settings',JSON.stringify(safeSettings));localStorage.removeItem('ieum-teacher-secret')}
function syncSignalNames(){}
function renderClassIdentity(){const {teacherName,schoolYear,grade,classNumber}=classSettings;$('#profileAvatar').textContent=teacherName.trim().charAt(0)||'교';$('#profileTeacher').textContent=`${teacherName} 선생님`;$('#profileClass').textContent=`${grade}학년 ${classNumber}반 담임`;$('#classEyebrow').textContent=`${schoolYear}학년도 · ${grade}학년 ${classNumber}반`}
function renderSettings(){const {teacherName,schoolYear,grade,classNumber,classId,students}=classSettings;$('#teacherName').value=teacherName;$('#schoolYear').value=schoolYear;$('#grade').value=grade;$('#classNumber').value=classNumber;$('#classId').value=classId||'';$('#teacherSecret').value='';$('#rosterCount').textContent=`${students.length}명`;$('#rosterBody').innerHTML=students.map((student,index)=>`<tr><td><input type="number" min="1" max="99" value="${student.number}" data-student-number="${index}" aria-label="${index+1}번째 학생 번호"></td><td><input maxlength="20" value="${escapeHTML(student.name)}" data-student-name="${index}" aria-label="${index+1}번째 학생 이름"></td><td><button class="remove-student" type="button" data-remove-student="${index}" aria-label="${escapeHTML(student.name)} 삭제">삭제</button></td></tr>`).join('')}
function collectSettingsForm(){const students=$$('#rosterBody tr').map((row,index)=>({number:Number(row.querySelector('[data-student-number]').value),name:row.querySelector('[data-student-name]').value.trim(),accessCode:classSettings.students[index]?.accessCode||''})).filter(student=>student.name).sort((a,b)=>a.number-b.number);return{teacherName:$('#teacherName').value.trim(),schoolYear:Number($('#schoolYear').value),grade:Number($('#grade').value),classNumber:Number($('#classNumber').value),classId:$('#classId').value.trim(),teacherSecret:$('#teacherSecret').value.trim(),students}}
function applySettings(){const next=collectSettingsForm();if(!next.teacherName||!next.students.length){showToast('교사 이름과 학생을 한 명 이상 입력해 주세요.');return}classSettings=next;persistClassSettings();syncSignalNames();renderClassIdentity();renderSettings();renderStudents();renderParticipationLink();renderHomeSignals();renderAnalysis($('.filter-tabs .active')?.dataset.filter||'all');showToast('학급 설정을 저장했습니다.')}
function renderParticipationLink(){const url=new URL('student.html',location.href);url.searchParams.set('class',classSettings.classId||`${classSettings.schoolYear}-${classSettings.grade}-${classSettings.classNumber}`);const code=document.querySelector('.copy-row code');if(code)code.textContent=url.href;$('#copyLink').dataset.link=url.href}
function renderResponses(responses){const month=selectedAnalysisMonth||new Date().toISOString().slice(0,7);const monthly=responses.filter(item=>monthOf(item)===month);const submittedNumbers=new Set(monthly.map(item=>Number(item.student_number||payloadOf(item).studentNumber)));const total=classSettings.students.length;const submitted=submittedNumbers.size;const rate=total?Math.round(submitted/total*100):0;$('#studentGrid').innerHTML=classSettings.students.map(student=>`<span class="student-chip ${submittedNumbers.has(Number(student.number))?'':'missing'}">${escapeHTML(student.name)}</span>`).join('');$('#surveyParticipation').textContent=`${submitted} / ${total}명 · ${monthLabel(month)}`;$('#surveyParticipationBar').style.width=`${rate}%`;$('#homeParticipation').innerHTML=`${submitted} <small>/ ${total}명</small>`;$('#homeParticipationBar').style.width=`${rate}%`;$('#homeParticipationText').textContent=`${monthLabel(month)} ${rate}% 참여 · 미제출 ${Math.max(0,total-submitted)}명`;$('#responseList').innerHTML=monthly.length?`<h4>${monthLabel(month)} 제출 원문</h4>`+monthly.map(item=>{const payload=payloadOf(item);const name=item.student_name||payload.studentName||classSettings.students.find(student=>student.number===payload.studentNumber)?.name||'학생';const help=payload.helpNow||'괜찮음';const worry=payload.studentState?.worryDetail||'작성 내용 없음';return`<details><summary><strong>${escapeHTML(name)}</strong><span class="tag ${/바로|즉시/.test(help)?'urgent':/이번 주/.test(help)?'week':'watch'}">${escapeHTML(help)}</span></summary><p>${escapeHTML(worry)}</p></details>`}).join(''):'<p class="muted">선택한 월에 저장된 응답이 없습니다.</p>';renderMonthlySurveyAccordion(responses)}
function renderMonthlySurveyAccordion(responses){const container=$('#monthlySurveyAccordion');if(!container)return;const months=[...new Set(responses.map(monthOf).filter(month=>/^\d{4}-\d{2}$/.test(month)))].sort().reverse();const total=classSettings.students.length;if(!months.length){container.innerHTML='<h4>월별 설문 현황</h4><p class="muted">저장된 월별 설문이 없습니다.</p>';return}container.innerHTML='<h4>월별 설문 현황</h4>'+months.map((month,index)=>{const rows=responses.filter(item=>monthOf(item)===month);const latest=latestByStudent(rows,month);const submitted=[...latest.keys()];const submittedSet=new Set(submitted);const rate=total?Math.round(submitted.length/total*100):0;const missing=classSettings.students.filter(student=>!submittedSet.has(Number(student.number)));const duplicateCount=Math.max(0,rows.length-submitted.length);const submittedNames=classSettings.students.filter(student=>submittedSet.has(Number(student.number))).map(student=>student.name);return`<details ${month===selectedAnalysisMonth||(!selectedAnalysisMonth&&index===0)?'open':''}><summary><strong>${monthLabel(month)}</strong><span class="tag ${rate>=80?'open':rate?'week':'watch'}">${submitted.length}/${total}명 · ${rate}%</span></summary><div class="evidence-box"><p><strong>제출 학생 ${submitted.length}명</strong></p><p>${submittedNames.length?submittedNames.map(escapeHTML).join(', '):'없음'}</p><p><strong>미제출 학생 ${missing.length}명</strong></p><p>${missing.length?missing.map(student=>escapeHTML(student.name)).join(', '):'없음'}</p><p class="muted">저장된 응답 ${rows.length}건${duplicateCount?` · 추가 제출 ${duplicateCount}건`:''}</p><button type="button" class="text-button" data-select-survey-month="${month}">이 월의 원문·분석 보기 →</button></div></details>`}).join('')}
function normalizeParticipationLabel(){const label=$('#surveyParticipation');if(label)label.textContent=label.textContent.split(' · ')[0];const responseList=$('#responseList');if(responseList)responseList.innerHTML=''}
function applyAnalysisMonth(){signals=analyzeResponses(allResponses,selectedAnalysisMonth);renderResponses(allResponses);normalizeParticipationLabel();renderAnalysisStatus();renderHomeSignals();renderAnalysis($('.filter-tabs .active')?.dataset.filter||'all');renderRelationshipsV2();renderRelationshipActions()}
async function refreshResponses(showNotice=true){if(!getTeacherSession()){if(showNotice)$('#authDialog').showModal();return}try{allResponses=await teacherRpc('teacher_get_responses_auth',{p_class_id:classSettings.classId});await refreshObservations();updateMonthSelector();applyAnalysisMonth();if(showNotice)showToast('로그인 계정의 응답과 관찰 기록을 불러왔습니다.')}catch(error){showToast(`자료를 불러오지 못했습니다: ${error.message}`)}}
async function syncRoster(){applySettings();if(!getTeacherSession()){showToast('교사 로그인이 필요합니다.');return}try{const count=await teacherRpc('teacher_sync_roster_auth',{p_class_id:classSettings.classId,p_students:classSettings.students.map(({number,name})=>({number,name}))});showToast(`${count}명의 명단을 DB에 동기화했습니다.`)}catch(error){showToast(`명단 동기화 실패: ${error.message}`)}}
function showToast(message){const el=$('#toast');el.textContent=message;el.classList.add('show');setTimeout(()=>el.classList.remove('show'),2200)}
function renderHomeSignals(){const groups=groupedSignals();const urgent=groups.filter(group=>group.type==='urgent').length;const weekStudents=groups.filter(group=>group.type==='week').length;const latest=latestByStudent(allResponses,selectedAnalysisMonth);const positive=[...latest.values()].filter(item=>{const peer=payloadOf(item).peerObservations||{};return peer.kind?.detail||peer.growth?.detail}).length;$('#homeUrgent').innerHTML=`${urgent} <small>명</small>`;$('#homeWeek').innerHTML=`${weekStudents} <small>명</small>`;$('#homePositive').innerHTML=`${positive} <small>건</small>`;$('#signalList').innerHTML=groups.length?groups.slice(0,3).map(group=>`<article class="signal-item ${group.type}"><i class="signal-bar"></i><div><span class="tag ${group.type}">${group.tag}</span><h3>${escapeHTML(group.name)} · ${group.items.length}개 확인 신호</h3><p>${escapeHTML(group.items.map(item=>item.title).join(' · '))}</p></div><button class="evidence-button" data-evidence-group="${group.ids.join(',')}">통합 근거 보기</button></article>`).join(''):'<p class="muted">선택한 월에 규칙 기반 지원 신호가 없습니다.</p>'}
function renderAnalysis(filter='all'){const allGroups=groupedSignals();const counts={all:allGroups.length,urgent:allGroups.filter(group=>group.type==='urgent').length,week:allGroups.filter(group=>group.type==='week').length,watch:allGroups.filter(group=>group.type==='watch').length};$$('.filter-tabs button').forEach(button=>{const labels={all:'전체',urgent:'즉시 확인',week:'이번 주',watch:'지속 관찰'};button.textContent=`${labels[button.dataset.filter]} ${counts[button.dataset.filter]}`});const visible=groupedSignals(filter);$('#analysisCards').innerHTML=visible.length?visible.map(group=>{const evidenceCount=group.items.reduce((sum,item)=>sum+item.evidence.length,0);return`<article class="analysis-card" data-type="${group.type}"><header><div><div class="analysis-card-tags"><span class="tag ${group.type}">${group.tag}</span><span class="change-badge">${escapeHTML(group.trend)}</span></div><h3>${escapeHTML(group.name)} · 통합 확인 카드</h3><div class="signal-summary">${group.items.map(item=>`<p><strong>▣ ${escapeHTML(item.title)}</strong><br>${escapeHTML(item.summary)}</p>`).join('')}</div>${group.protectiveFactors.length?`<div class="protective-factors"><strong>긍정적 보호요인</strong><p>${group.protectiveFactors.map(item=>`✓ ${escapeHTML(item)}`).join(' · ')}</p></div>`:''}</div></header><footer><span class="evidence-count">신호 ${group.items.length}개 · 근거 ${evidenceCount}개</span><button class="evidence-button" data-evidence-group="${group.ids.join(',')}">통합 근거와 관찰 제안</button></footer></article>`}).join(''):'<div class="panel"><p class="muted">선택한 조건에 해당하는 실제 응답 신호가 없습니다.</p></div>'}
function renderStudents(){renderResponses([])}
function getObservations(){return JSON.parse(localStorage.getItem('ieum-observations')||'null')||[]}
function saveObservations(items){localStorage.setItem('ieum-observations',JSON.stringify(items));renderObservations()}
function observationFromDb(row){const number=row.student_number===null?null:Number(row.student_number),student=classSettings.students.find(item=>Number(item.number)===number);return{id:row.id,status:row.status,studentNumber:number,student:student?.name||(number?`${number}번`:'학급 전체'),title:row.title,detail:row.planned_action||row.observed_fact||'',date:row.follow_up_date||row.survey_month?.slice(0,7)||'날짜 미정',observedFact:row.observed_fact||'',teacherInterpretation:row.teacher_interpretation||'',interviewNote:row.interview_note||'',followUp:row.follow_up||'',followUpDate:row.follow_up_date||''}}
function observationPayload(item){const matched=classSettings.students.find(student=>student.name===item.student)?.number,studentNumber=Number(item.studentNumber||matched)||null;return{id:item.id,studentNumber,surveyMonth:`${selectedAnalysisMonth||new Date().toISOString().slice(0,7)}-01`,title:item.title,plannedAction:item.detail||'',observedFact:item.observedFact||'',teacherInterpretation:item.teacherInterpretation||'',interviewNote:item.interviewNote||'',followUp:item.followUp||'',followUpDate:item.followUpDate||'',status:item.status||'todo'}}
async function persistObservation(item){const previousId=item.id,id=await teacherRpc('teacher_save_observation_auth',{p_class_id:classSettings.classId,p_observation:observationPayload(item)});item.id=id;const items=getObservations(),saved=items.find(row=>String(row.id)===String(previousId));if(saved)saved.id=id;saveObservations(items);return id}
async function refreshObservations(){const local=getObservations().filter(item=>![1,2,3].includes(Number(item.id)));let rows=await teacherRpc('teacher_get_observations_auth',{p_class_id:classSettings.classId});if(!rows.length&&local.length){for(const item of local){item.id=crypto.randomUUID();await persistObservation(item)}rows=await teacherRpc('teacher_get_observations_auth',{p_class_id:classSettings.classId})}saveObservations(rows.map(observationFromDb))}
function renderObservations(){const items=getObservations();const cols=[['todo','관찰 예정'],['doing','관찰 중'],['done','확인 완료']];$('#observationBoard').innerHTML=cols.map(([key,label])=>{const list=items.filter(i=>i.status===key);return `<section class="observation-column"><div class="column-head"><h3>${label}</h3><span>${list.length}</span></div>${list.map(i=>`<article class="observation-card"><span class="tag ${key==='done'?'open':key==='doing'?'week':'watch'}">${i.student}</span><h4>${i.title}</h4><p>${i.detail}</p><footer><span>${i.date}</span>${key!=='done'?`<button class="text-button" data-advance="${i.id}">다음 단계 →</button>`:'<span>✓ 확인됨</span>'}</footer></article>`).join('')||'<p class="muted">기록이 없습니다.</p>'}</section>`}).join('')}
function openEvidence(id){const s=signals.find(x=>x.id===Number(id));if(!s)return;$('#dialogTitle').textContent=`${s.name} · ${s.title}`;$('#dialogContent').innerHTML=`<h3>연결된 근거</h3>${s.evidence.map(e=>`<div class="evidence-box">${escapeHTML(e)}</div>`).join('')}<h3>가능한 해석</h3><div class="hypotheses">${s.hypotheses.map(h=>`<span>${escapeHTML(h)}</span>`).join('')}</div><h3>추천 관찰</h3><p>${escapeHTML(s.observation)}</p><div class="notice warning"><span>!</span><p>가능성에 대한 가설입니다. 원문 검토와 실제 관찰·대화로 확인해 주세요.</p></div>`;$('#saveObservation').dataset.signal=id;delete $('#saveObservation').dataset.signalGroup;$('#evidenceDialog').showModal()}
function openEvidenceGroup(ids){const items=String(ids).split(',').map(Number).map(id=>signals.find(signal=>signal.id===id)).filter(Boolean);if(!items.length)return;const name=items[0].name;$('#dialogTitle').textContent=`${name} · 통합 근거`;$('#dialogContent').innerHTML=items.map(item=>`<section><span class="tag ${item.type}">${item.tag}</span><h3>▣ 계산·분류 결과</h3><p><strong>${escapeHTML(item.title)}</strong><br>${escapeHTML(item.summary)}</p><h3>“ ” 연결된 학생 응답·계산 근거</h3>${item.evidence.map(e=>`<div class="evidence-box">${escapeHTML(e)}</div>`).join('')}<h3>? 가능한 해석</h3><div class="hypotheses">${item.hypotheses.map(h=>`<span>${escapeHTML(h)}</span>`).join('')}</div><h3>✓ 교사 확인 제안</h3><p>${escapeHTML(item.observation)}</p></section>`).join('<hr>')+`<div class="notice warning"><span>!</span><p>계산 결과와 가능성에 대한 가설입니다. 원문 검토와 실제 관찰·대화로 확인해 주세요.</p></div>`;$('#saveObservation').dataset.signal=items[0].id;$('#saveObservation').dataset.signalGroup=items.map(item=>item.id).join(',');$('#evidenceDialog').showModal()}
$$('.nav-item').forEach(btn=>btn.addEventListener('click',()=>{const view=btn.dataset.view;$$('.nav-item').forEach(x=>x.classList.toggle('active',x===btn));$$('.view').forEach(x=>x.classList.toggle('active',x.id===`view-${view}`));$('#pageTitle').textContent=pageTitles[view];if(view==='settings')renderSettings();$('#sidebar').classList.remove('open');window.scrollTo(0,0)}));
document.addEventListener('click',async e=>{const evidenceGroup=e.target.closest('[data-evidence-group]');if(evidenceGroup)openEvidenceGroup(evidenceGroup.dataset.evidenceGroup);else{const evidence=e.target.closest('[data-evidence]');if(evidence)openEvidence(evidence.dataset.evidence)}const closer=e.target.closest('[data-close]');if(closer)closer.closest('dialog').close();const go=e.target.closest('[data-go]');if(go)$(`.nav-item[data-view="${go.dataset.go}"]`).click();const advance=e.target.closest('[data-advance]');if(advance){const items=getObservations();const item=items.find(i=>String(i.id)===String(advance.dataset.advance));if(item){item.status=item.status==='todo'?'doing':'done';saveObservations(items);try{await persistObservation(item);showToast('관찰 상태를 DB에 저장했습니다.')}catch(error){showToast(`DB 저장 실패: ${error.message}`)}}}const remove=e.target.closest('[data-remove-student]');if(remove){classSettings=collectSettingsForm();classSettings.students.splice(Number(remove.dataset.removeStudent),1);renderSettings();showToast('명단에서 삭제했습니다. 저장 버튼을 눌러 확정하세요.')}});
$('.filter-tabs').addEventListener('click',e=>{if(e.target.tagName!=='BUTTON')return;$$('.filter-tabs button').forEach(b=>b.classList.toggle('active',b===e.target));renderAnalysis(e.target.dataset.filter)});
document.addEventListener('click',event=>{const monthButton=event.target.closest('[data-select-survey-month]');if(!monthButton)return;selectedAnalysisMonth=monthButton.dataset.selectSurveyMonth;$('#analysisMonth').value=selectedAnalysisMonth;$('#surveyMonth').value=selectedAnalysisMonth;applyAnalysisMonth();showToast(`${monthLabel(selectedAnalysisMonth)} 현황을 선택했습니다.`)});
$('#saveObservation').addEventListener('click',async e=>{const groupIds=String(e.target.dataset.signalGroup||e.target.dataset.signal).split(',').map(Number);const selected=groupIds.map(id=>signals.find(signal=>signal.id===id)).filter(Boolean);const s=selected[0];if(!s)return;const items=getObservations(),item={id:crypto.randomUUID(),status:'todo',studentNumber:s.studentNumber,student:s.name,title:selected.length>1?`${selected.length}개 신호 통합 확인`:s.title,detail:selected.map(item=>item.observation).join(' / '),date:'이번 주'};items.unshift(item);saveObservations(items);delete e.target.dataset.signalGroup;$('#evidenceDialog').close();try{await persistObservation(item);showToast('관찰 과제를 DB에 저장했습니다.')}catch(error){showToast(`브라우저에는 저장했지만 DB 저장에 실패했습니다: ${error.message}`)}});
