$('#applyRosterPaste').addEventListener('click',()=>{const parsed=$('#rosterPaste').value.split(/\r?\n/).map(line=>line.trim()).filter(Boolean).map((line,index)=>{const parts=line.split(/[,\t]/).map(part=>part.trim());const hasNumber=parts.length>1&&!Number.isNaN(Number(parts[0]));return{number:hasNumber?Number(parts[0]):index+1,name:hasNumber?parts.slice(1).join(' '):parts.join(' ')}}).filter(student=>student.name);if(!parsed.length){showToast('붙여넣을 학생 이름을 입력해 주세요.');return}classSettings={...collectSettingsForm(),students:parsed};renderSettings();$('#pasteDialog').close();showToast(`${parsed.length}명의 명단을 불러왔습니다. 저장 버튼을 눌러 확정하세요.`)});
document.addEventListener('click',event=>{if(event.target.id!=='toggleNames'||(!event.target.closest('#relationContent')&&!event.target.closest('#relationPreview')))return;const network=event.target.closest('.network-panel').querySelector('.network');const show=network.classList.toggle('show-names');event.target.textContent=show?'이름 숨기기':'이름 표시';network.querySelectorAll('[data-student-node]').forEach(node=>{const text=node.querySelector('text');text.textContent=show?node.querySelector('title').textContent:text.textContent.charAt(0)})});
const steps=[`<div class="survey-question"><p class="eyebrow">나의 학교생활</p><h2>이번 달에 친구를 존중하며 이야기했나요?</h2><p>가장 가까운 답을 골라 주세요. 점수는 평가나 순위에 사용되지 않아요.</p><div class="rating-options">${[1,2,3,4,5].map((n,i)=>`<label><input type="radio" name="rating" value="${n}" ${n===4?'checked':''}><strong>${n}점</strong> · ${['거의 못했어요','조금 어려웠어요','보통이에요','잘했어요','매우 잘했어요'][i]}</label>`).join('')}</div></div>`,`<div class="survey-question"><p class="eyebrow">내 마음 표현하기</p><h2>요즘 학교생활에서 마음에 걸리는 일이 있나요?</h2><p>직접 겪은 일과 들은 일을 구분해서, 기억나는 만큼만 적어도 괜찮아요.</p><textarea placeholder="언제, 어디서, 어떤 일이 있었는지 적어 주세요."></textarea></div>`,`<div class="survey-question"><p class="eyebrow">도움 요청</p><h2>선생님의 도움이 지금 필요한가요?</h2><p>급한 도움이 필요하면 설문을 기다리지 말고 바로 선생님께 알려 주세요.</p><div class="help-choice"><label><input type="radio" name="help" checked> 지금은 괜찮아요.</label><label><input type="radio" name="help"> 이번 주에 이야기하고 싶어요.</label><label><input type="radio" name="help"> 바로 도와주세요.</label></div></div>`];let step=0;
function renderStep(){ $('#surveyStep').innerHTML=steps[step];$('#stepLabel').textContent=`${step+1} / ${steps.length}`;$('#surveyProgress').style.width=`${(step+1)/steps.length*100}%`;$('#prevStep').style.visibility=step?'visible':'hidden';$('#nextStep').textContent=step===steps.length-1?'제출하기':'다음'}
$('#openStudentSurvey').addEventListener('click',event=>{event.currentTarget.href=$('#copyLink').dataset.link});
$('#prevStep').addEventListener('click',()=>{if(step){step--;renderStep()}});$('#nextStep').addEventListener('click',()=>{if(step<steps.length-1){step++;renderStep()}else{$('#studentDialog').close();showToast('미리보기 설문이 제출되었습니다.')}});
